void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var e = vector<pair<ll, tuple<int, int, int>>>(m + 1);
	fa(i, 1, m) {
		ll u, v, w; cin >> u >> v >> w;
		e[i] = { w, { u, v, i } };
	}

	sort(all1(e));
	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};

	var g = vector<vector<pll>>(n + 1);
	var vis = vector<bool>(m + 1);
	ll ans = 0, cnt = n - 1ll;
	fa(i, 1, m) {
		const var& [w, tmp] = e[i];
		const var& [x, y, id] = tmp;
		int e1 = find(find, x);
		int e2 = find(find, y);
		if (e1 != e2) {
			g[x].pb({ y,w }), g[y].pb({ x,w });
			s[e2] = e1;
			ans += w;
			vis[id] = 1;
			cnt--;
			if (cnt == 0)break;
		}
	}

	var dp = Vec2<ll>(n + 1, 21);
	var dep = vector<int>(n + 1);
	var p = Vec2<int>(n + 1, 21);
	var dfs = [&](var dfs, int now, int fa)->void {
		dep[now] = dep[fa] + 1;
		p[now][0] = fa;
		for (const var& [to, w] : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			dp[to][0] = w;
		}
		};
	dfs(dfs, 1, 0);

	var lca = [&dep, &p](int x, int y)->int {
		if (dep[x] < dep[y])swap(x, y);
		for (int i = 20; i >= 0; i--)
			if (dep[x] - (1 << i) >= dep[y])
				x = p[x][i];
		if (x == y) return x;
		for (int i = 20; i >= 0; i--)
			if (p[x][i] != p[y][i])
				x = p[x][i], y = p[y][i];
		return p[x][0];
		};

	var jump = [&](int now, int cha)->ll {
		ll res = 0;
		fa(i, 0, 20)if (cha & (1 << i)) {
			res = max(res, dp[now][i]);
			now = p[now][i];
		}
		return res;
		};

	fa(j, 1, 20) {
		fa(i, 1, n) {
			p[i][j] = p[p[i][j - 1]][j - 1];
			dp[i][j] = max(dp[i][j - 1], dp[p[i][j - 1]][j - 1]);
		}
	}

	var anss = vector<ll>(m + 1);
	fa(i, 1, m) {
		const var& [w, tmp] = e[i];
		const var& [x, y, id] = tmp;
		if (vis[id])anss[id] = ans;
		else {
			ll res = ans + w;
			int l = lca(x, y);
			if (l == y)res -= jump(x, dep[x] - dep[l]);
			else if (l == x)res -= jump(y, dep[y] - dep[l]);
			else res -= max(jump(x, dep[x] - dep[l]), jump(y, dep[y] - dep[l]));
			anss[id] = res;
		}
	}

	fa(i, 1, m)cout << anss[i] << endl;
	return;
}
